def create_configuration_directories():
    """Create all necessary configuration directories for the toolkit."""
    directories = [CONFIG_DIR, RESOURCES_DIR, LOG_DIR]
    for directory in directories:
        if not os.path.exists(directory):
            os.makedirs(directory, exist_ok=True)
            print(f"[Setup] Created directory: {directory}")
        else:
            print(f"[Setup] Directory already exists: {directory}")


def download_additional_resources():
    """Download additional resource files needed by the toolkit."""
    create_configuration_directories()

    for filename, url in ADDITIONAL_RESOURCES.items():
        dest_path = os.path.join(RESOURCES_DIR, filename)
        if os.path.exists(dest_path):
            print(f"[Setup] Resource already exists, skipping: {filename}")
            continue
        try:
            print(f"[Setup] Downloading resource: {filename} from {url}")
            urllib.request.urlretrieve(url, dest_path)
            print(f"[Setup] Successfully downloaded: {filename}")
        except Exception as e:
            print(f"[Setup] Warning: Could not download {filename}: {e}")
            # Create a placeholder file so the package can still function
            _create_placeholder_resource(dest_path, filename)


def _create_placeholder_resource(dest_path, filename):
    """Create a placeholder resource file when download fails."""
    try:
        if filename.endswith(".yaml"):
            content = "# Placeholder configuration - replace with actual config\n"
            content += "settings:\n  placeholder: true\n"
        elif filename.endswith(".json"):
            content = json.dumps({"placeholder": True, "note": "Replace with actual resource"}, indent=2)
        else:
            content = "# Placeholder resource file\n"

        with open(dest_path, "w") as f:
            f.write(content)
        print(f"[Setup] Created placeholder for: {filename}")
    except Exception as e:
        print(f"[Setup] Warning: Could not create placeholder for {filename}: {e}")


def setup_environment_variables():
    """Set up environment variables and persist them to a config file."""
    create_configuration_directories()

    # Load existing env config if present
    existing_config = {}
    if os.path.exists(ENV_FILE):
        try:
            with open(ENV_FILE, "r") as f:
                existing_config = json.load(f)
        except (json.JSONDecodeError, IOError):
            existing_config = {}

    # Merge defaults with existing (existing values take precedence)
    merged_config = {**DEFAULT_ENV_VARS, **existing_config}

    # Set environment variables for current process
    for key, value in merged_config.items():
        os.environ[key] = str(value)
        print(f"[Setup] Set environment variable: {key}={value}")

    # Persist to config file
    try:
        with open(ENV_FILE, "w") as f:
            json.dump(merged_config, f, indent=2)
        print(f"[Setup] Environment configuration saved to: {ENV_FILE}")
    except IOError as e:
        print(f"[Setup] Warning: Could not save environment config: {e}")

    # Generate shell profile snippet
    _generate_shell_profile_snippet(merged_config)


def _generate_shell_profile_snippet(env_vars):
    """Generate a shell snippet that users can source to load env vars."""
    shell_snippet_path = os.path.join(CONFIG_DIR, "env_setup.sh")
    try:
        with open(shell_snippet_path, "w") as f:
            f.write("#!/bin/bash\n")
            f.write("# Auto-generated by internal_toolkit setup\n")
            f.write(f"# Source this file to set up environment variables:\n")
            f.write(f"#   source {shell_snippet_path}\n\n")
            for key, value in env_vars.items():
                f.write(f'export {key}="{value}"\n')
        os.chmod(shell_snippet_path, 0o755)
        print(f"[Setup] Shell environment script created: {shell_snippet_path}")
        print(f"[Setup] Run 'source {shell_snippet_path}' to load environment variables.")
    except (IOError, OSError) as e:
        print(f"[Setup] Warning: Could not create shell snippet: {e}")


